module up_down_counter (
    input clk,
    input reset,
    input up_down,
    output [3:0] count );reg [3:0] cnt_reg;

always @(posedge clk) begin
    if (reset)
        cnt_reg <= 4'b0000;
    else if (up_down)
        cnt_reg <= cnt_reg + 1;
    else
        cnt_reg <= cnt_reg - 1;
end

assign count = cnt_reg;

endmodule
